3082 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3083                                                FPClassTest DemandedMask,
3084                                                KnownFPClass &Known,
3085                                                unsigned Depth) {
3086   Use &U = I->getOperandUse(OpNo);
3087   Value *V = U.get();
3088   Type *VTy = V->getType();
3089 
3090   if (DemandedMask == fcNone) {
3091     if (isa<UndefValue>(V))
3092       return false;
3093     replaceUse(U, PoisonValue::get(VTy));
3094     return true;
3095   }
3096 
3097   // Handle constant
3098   Instruction *VInst = dyn_cast<Instruction>(V);
3099   if (!VInst) {
3100     // Handle constants and arguments
3101     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3102 
3103     FPClassTest ValidResults = DemandedMask & Known.KnownFPClasses;
3104     if (ValidResults == fcNone) {
3105       if (isa<UndefValue>(V))
3106         return false;
3107       replaceUse(U, PoisonValue::get(VTy));
3108       return true;
3109     }
3110 
3111     // Do not try to replace values which are already constants (unless we are
3112     // folding to poison). Doing so could promote poison elements to non-poison
3113     // constants.
3114     if (isa<Constant>(V))
3115       return false;
3116 
3117     Value *FoldedToConst = getFPClassConstant(VTy, ValidResults);
3118     if (!FoldedToConst || FoldedToConst == V)
3119       return false;
3120 
3121     replaceUse(U, FoldedToConst);
3122     return true;
3123   }
3124 
3125   if (Depth == MaxAnalysisRecursionDepth)
3126     return false;
3127 
3128   Value *NewVal;
3129 
3130   if (VInst->hasOneUse()) {
3131     // If the instruction has one use, we can directly simplify it.
3132     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3133   } else {
3134     // If there are multiple uses of this instruction, then we can simplify
3135     // VInst to some other value, but not modify the instruction.
3136     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3137                                                 Depth);
3138   }
3139 
3140   if (!NewVal)
3141     return false;
3142   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3143     salvageDebugInfo(*OpInst);
